CREATE TRIGGER [dbo].[Order_History]ON [dbo].[Order]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.OrderId IS NOT NULL AND d.OrderId IS NULL THEN 'I' 		WHEN i.OrderId IS NOT NULL AND d.OrderId IS NOT NULL THEN 'U' 		WHEN i.OrderId IS NULL AND d.OrderId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.OrderId = d.OrderId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_Order([OrderId], [Number], [OrderStateId], [CustomerId], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [OrderId], [Number], [OrderStateId], [CustomerId], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_Order([OrderId], [Number], [OrderStateId], [CustomerId], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [OrderId], [Number], [OrderStateId], [CustomerId], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND